  ('elementary-0a2fc18c-moex-00587', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '古典學派主張短期總合供給曲線是垂直線，而凱因斯學派主張短期總合供給曲線具有正斜率。造成這兩 學派有前述主張差異的原因是下列那一項？', '["古典學派認為工資調整速度很快，而凱因斯學派認為勞動市場存在著到期時間不一的工資契約", "古典學派認為物價調整速度很快，而凱因斯學派認為債券與貨幣是完全替代", "古典學派認為商品市場是完全競爭，而凱因斯學派認為經濟的主要干擾來自需求面", "古典學派認為經濟的主要干擾來自供給面，而凱因斯學派認為民眾具有貨幣幻覺（moneyillusion）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:16+00:00", "source_pdf_sha1": "64309f0e4e1f", "answer_pdf_sha1": "e301272da8a3", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
